pub fn process_deposit_all_token_types(
    program_id: &Pubkey,
    pool_token_amount: u64,
    accounts: &[AccountInfo],
) -> ProgramResult {
    let token_swap = SwapVersion::unpack(&swap_info.data.borrow())?;
    let calculator = &token_swap.swap_curve().calculator;

    let token_a = Self::unpack_token_account(token_a_info, token_swap.token_program_id())?;
    let token_b = Self::unpack_token_account(token_b_info, token_swap.token_program_id())?;
    let pool_mint = Self::unpack_mint(pool_mint_info, token_swap.token_program_id())?;

    let results = calculator
        .pool_tokens_to_trading_tokens(
            pool_token_amount as u128,
            pool_mint.supply as u128,
            token_a.amount as u128,
            token_b.amount as u128,
            RoundDirection::Ceiling,
        )
        .ok_or(SwapError::ZeroTradingTokens)?;

    let token_a_amount = results.token_a_amount as u64;
    let token_b_amount = results.token_b_amount as u64;

    Self::token_transfer(swap_info.key, token_a_program_info.clone(),
        source_a_info.clone(), token_a_mint_info.clone(), token_a_info.clone(),
        user_transfer_authority_info.clone(), token_swap.bump_seed(),
        token_a_amount, decimals_a)?;

    Ok(())
}
